// OpenCL kernel for streamcluster pgain computation
// Translated from OpenMP source code

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

// Kernel 1: Compute distances and update switch_membership and work_mem
__kernel void pgain_compute_distances(
    __global const Point_Struct* p,
    __global const float* coord,
    __global float* work_mem,
    __global const int* center_table,
    __global char* switch_membership,
    __local float* local_coord,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    // Load x point coordinates into local memory
    for (int d = 0; d < dim; d++) {
        local_coord[d] = coord[x * dim + d];
    }

    // Compute distance from point i to point x
    float dist_result = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - local_coord[d];
        dist_result += diff * diff;
    }

    float x_cost = dist_result * p[i].weight;
    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += (x_cost - current_cost);
    } else {
        int assign = (int)p[i].assign;
        int center_idx = center_table[assign];
        if (center_idx >= 0 && center_idx < K) {
            work_mem[i * (K + 1) + center_idx] += (current_cost - x_cost);
        }
    }
}

// Kernel 2: Process centers to determine which should be closed
__kernel void pgain_process_centers(
    __global const int* center_table,
    __global float* work_mem,
    __global float* gl_lower,
    __global char* is_center,
    int num,
    int K,
    float z)
{
    int i = get_global_id(0);
    if (i >= num) return;

    if (is_center[i] != 0) {
        int center_idx = center_table[i];
        if (center_idx >= 0 && center_idx < K) {
            float low = z;
            for (int j = 0; j < num; j++) {
                low += work_mem[j * (K + 1) + center_idx];
            }
            gl_lower[center_idx] = low;
        }
    }
}

// Kernel 3: Update point assignments based on gain computation
__kernel void pgain_update_assignments(
    __global Point_Struct* p,
    __global const float* coord,
    __global const char* switch_membership,
    __global const int* center_table,
    __global const float* gl_lower,
    __global char* is_center,
    __local float* local_coord,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    // Load x point coordinates into local memory
    for (int d = 0; d < dim; d++) {
        local_coord[d] = coord[x * dim + d];
    }

    // Compute distance from point i to point x
    float dist_result = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - local_coord[d];
        dist_result += diff * diff;
    }

    int assign = (int)p[i].assign;
    int center_idx = center_table[assign];
    bool close_center = (center_idx >= 0 && center_idx < K && gl_lower[center_idx] > 0);

    if (switch_membership[i] == 1 || close_center) {
        p[i].cost = dist_result * p[i].weight;
        p[i].assign = x;
    }

    // Update is_center for current point
    if (is_center[i] != 0) {
        center_idx = center_table[i];
        if (center_idx >= 0 && center_idx < K && gl_lower[center_idx] > 0) {
            is_center[i] = 0;
        }
    }

    // Set is_center for x point
    if (i == x) {
        is_center[i] = 1;
    }
}
